/**
 * @param {number} l
 * @param {number} r
 * @param {string} directions
 * @return {number}
 */
function solve(l, r, directions) {

    /**
     * Checks if integer x is a "good" integer based on the traversal rules.
     * @param {number} x The integer to check.
     * @param {string} directions The direction string.
     * @returns {boolean} True if x is a good integer, false otherwise.
     */
    function isGood(x, directions) {
        const DIGIT_LENGTH = 16;
        const GRID_SIZE = 4;

        // 1. Padding and Grid Mapping
        let xStr = x.toString();
        let paddedStr = xStr.padStart(DIGIT_LENGTH, '0');

        // Build the 4x4 grid G
        let grid = Array(GRID_SIZE).fill(0).map(() => Array(GRID_SIZE).fill(0));

        for (let i = 0; i < DIGIT_LENGTH; i++) {
            const digit = parseInt(paddedStr[i]);
            const row = Math.floor(i / GRID_SIZE);
            const col = i % GRID_SIZE;
            grid[row][col] = digit;
        }

        // 2. Path Traversal
        let r_curr = 0;
        let c_curr = 0;
        let sequence = [];

        // Start position
        sequence.push(grid[0][0]);

        // Apply 6 directions
        for (let i = 0; i < 6; i++) {
            const move = directions[i];

            let r_next = r_curr;
            let c_next = c_curr;

            if (move === 'D') {
                r_next += 1;
            } else if (move === 'R') {
                c_next += 1;
            }

            // Update current position
            r_curr = r_next;
            c_curr = c_next;

            // Assuming valid movement leads to a cell within bounds [0, 3] x [0, 3]
            // If bounds checking was necessary (e.g., clamping or stopping), it would go here.
            // Based on examples, we assume the calculated (r_curr, c_curr) is always valid.
            if (r_curr >= 0 && r_curr < GRID_SIZE && c_curr >= 0 && c_curr < GRID_SIZE) {
                sequence.push(grid[r_curr][c_curr]);
            } else {
                // This branch should ideally not be hit based on problem structure demanding length 7
                // If it is hit, the path is invalid according to the expected length, but we must proceed.
                // For safety based on problem constraints, we assume valid paths for simplicity.
                // If we hit this, the sequence length will be less than 7, failing the non-decreasing check implicitly 
                // or requiring specific handling not detailed in the prompt. We stick to the successful path logic.
                break; 
            }
        }

        // Ensure we have exactly 7 elements as specified
        if (sequence.length !== 7) return false;


        // 3. Check Monotonicity
        for (let i = 0; i < 6; i++) {
            if (sequence[i] > sequence[i+1]) {
                return false; // Not non-decreasing
            }
        }

        return true; // Non-decreasing
    }

    let goodCount = 0;

    // Iterate from l to r
    for (let x = l; x <= r; x++) {
        if (isGood(x, directions)) {
            goodCount++;
        }
    }

    return goodCount;
}

